import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Login2.css";

const Login2 = () => {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [errors, setErrors] = useState({});

  const handleLogin = (e) => {
    e.preventDefault();

    const validationErrors = {};
    const trimmedEmail = email.trim();
    const trimmedPassword = password.trim();

    if (!trimmedEmail) validationErrors.email = "Email / Username is required";
    if (!trimmedPassword) validationErrors.password = "Password is required";

    setErrors(validationErrors);

    if (Object.keys(validationErrors).length !== 0) return;

    // Get all users
    const users = JSON.parse(localStorage.getItem("users")) || [];

    // IMPORTANT:
    // Allow login using either EMAIL or USERNAME
    const user = users.find(
      (u) =>
        (u.email === trimmedEmail || u.username === trimmedEmail) &&
        u.password === trimmedPassword
    );

    if (!user) {
      alert("Invalid credentials");
      return;
    }

    // Store logged in user
    localStorage.setItem("loggedInUser", JSON.stringify(user));

    alert("Login Successful");

    // Role-based navigation (ready for future routing if needed)
    navigate("/dashboard");
  };

  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleLogin}>
        <h2>Login</h2>

        <div className="form-group">
          <label>Email / Username</label>
          <input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Enter email or username"
          />
          {errors.email && <span className="error">{errors.email}</span>}
        </div>

        <div className="form-group">
          <label>Password</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Enter password"
          />
          {errors.password && (
            <span className="error">{errors.password}</span>
          )}
        </div>

        <button type="submit">Login</button>
      </form>
    </div>
  );
};

export default Login2;
